import java.io.*;
import java.util.*;

public class Main {
    private static int dfs(int node, int[] left, int[] right) {
        if (node == 0) return -1; // null node contributes -1 so leaf becomes 0
        int hl = dfs(left[node], left, right);
        int hr = dfs(right[node], left, right);
        return Math.max(hl, hr) + 1;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        String line = br.readLine();
        if (line == null || line.isEmpty()) return;
        int T = Integer.parseInt(line.trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            int[] left = new int[N + 1];
            int[] right = new int[N + 1];
            boolean[] isChild = new boolean[N + 1];
            for (int i = 0; i < N - 1; i++) {
                StringTokenizer st = new StringTokenizer(br.readLine());
                int p = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                char dir = st.nextToken().charAt(0);
                if (dir == 'L') left[p] = c; else right[p] = c;
                isChild[c] = true;
            }
            int root = 1;
            for (int i = 1; i <= N; i++) {
                if (!isChild[i]) { root = i; break; }
            }
            out.append(dfs(root, left, right)).append('\n');
        }
        System.out.print(out.toString());
    }
}

